from itertools import product

# 예제 1: Y = AB + AB' + A'B  ->  A+B
def orig1(A, B):
    return A * B + A * (1 - B) + (1 - A) * B

for A, B in product([0, 1], repeat=2):
    assert (1 if orig1(A, B) >= 1 else 0) == max(A, B)
print("예제1 확인: AB+AB'+A'B = A+B")

# 예제 2: Y = A + ABC + A'BC + AD + AD' + A'B  ->  A+B
def orig2(A, B, C, D):
    return max(A, A * B * C, (1 - A) * B * C, A * D, A * (1 - D), (1 - A) * B)

for A, B, C, D in product([0, 1], repeat=4):
    assert orig2(A, B, C, D) == max(A, B)
print("예제2 확인: A+ABC+A'BC+AD+AD'+A'B = A+B")
